import React, { useState, useEffect } from "react";
import { useNavigate, Link } from "react-router-dom";
import {
  Box,
  Typography,
  TextField,
  Button,
  Paper,
  Tab,
  Tabs,
  InputAdornment,
  IconButton,
  Alert,
  CircularProgress,
} from "@mui/material";
import LocalHospitalIcon from "@mui/icons-material/LocalHospital";
import EmailIcon from "@mui/icons-material/Email";
import LockIcon from "@mui/icons-material/Lock";
import PersonIcon from "@mui/icons-material/Person";
import PhoneIcon from "@mui/icons-material/Phone";
import VisibilityIcon from "@mui/icons-material/Visibility";
import VisibilityOffIcon from "@mui/icons-material/VisibilityOff";

const PRIMARY = "#1976d2";
const PRIMARY_DARK = "#1565c0";
const PRIMARY_LIGHT = "#e3f2fd";
const BG = "#f0f7ff";

export default function PatientLogin() {
  const navigate = useNavigate();
  const [tab, setTab] = useState(0); // 0 = login, 1 = register
  const [showPass, setShowPass] = useState(false);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const [success, setSuccess] = useState("");

  const [loginForm, setLoginForm] = useState({ email: "", password: "" });
  const [registerForm, setRegisterForm] = useState({
    fullName: "",
    email: "",
    phone: "",
    password: "",
    confirmPassword: "",
  });

  useEffect(() => {
    if (localStorage.getItem("isPatientLoggedIn") === "true") {
      navigate("/patient/dashboard");
    }
  }, [navigate]);

  const handleLogin = () => {
    setError("");
    if (!loginForm.email || !loginForm.password) {
      setError("Please fill all fields.");
      return;
    }
    const patients = JSON.parse(localStorage.getItem("patients") || "[]");
    const found = patients.find(
      (p) => p.email === loginForm.email && p.password === loginForm.password,
    );
    if (!found) {
      setError("Invalid email or password.");
      return;
    }

    setLoading(true);
    setTimeout(() => {
      localStorage.setItem("isPatientLoggedIn", "true");
      localStorage.setItem("patientName", found.fullName);
      localStorage.setItem("patientEmail", found.email);
      navigate("/patient/dashboard");
    }, 1000);
  };

  const handleRegister = () => {
    setError("");
    setSuccess("");
    const { fullName, email, phone, password, confirmPassword } = registerForm;
    if (!fullName || !email || !phone || !password || !confirmPassword) {
      setError("Please fill all fields.");
      return;
    }
    if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email)) {
      setError("Please enter a valid email.");
      return;
    }
    if (!/^\d{10}$/.test(phone)) {
      setError("Phone number must be exactly 10 digits.");
      return;
    }
    if (password.length < 6) {
      setError("Password must be at least 6 characters.");
      return;
    }
    if (password !== confirmPassword) {
      setError("Passwords do not match.");
      return;
    }

    const patients = JSON.parse(localStorage.getItem("patients") || "[]");
    if (patients.find((p) => p.email === email)) {
      setError("An account with this email already exists.");
      return;
    }

    setLoading(true);
    setTimeout(() => {
      const newPatient = { id: Date.now(), fullName, email, phone, password };
      localStorage.setItem(
        "patients",
        JSON.stringify([...patients, newPatient]),
      );
      setLoading(false);
      setSuccess("Account created successfully! Please login.");
      setRegisterForm({
        fullName: "",
        email: "",
        phone: "",
        password: "",
        confirmPassword: "",
      });
      setTab(0);
    }, 1000);
  };

  const fieldSx = {
    mb: 2,
    "& .MuiOutlinedInput-root": {
      borderRadius: 2,
      "&.Mui-focused fieldset": { borderColor: PRIMARY },
    },
    "& label.Mui-focused": { color: PRIMARY },
  };

  return (
    <Box
      sx={{
        minHeight: "100vh",
        background: `linear-gradient(135deg, ${PRIMARY_DARK} 0%, ${PRIMARY} 50%, #42a5f5 100%)`,
        display: "flex",
        alignItems: "center",
        justifyContent: "center",
        p: 2,
      }}
    >
      <Box sx={{ width: "100%", maxWidth: 460 }}>
        {/* Logo */}
        <Box sx={{ textAlign: "center", mb: 3 }}>
          <Box
            sx={{
              width: 64,
              height: 64,
              borderRadius: "50%",
              bgcolor: "rgba(255,255,255,0.2)",
              mx: "auto",
              mb: 1.5,
              display: "flex",
              alignItems: "center",
              justifyContent: "center",
            }}
          >
            <LocalHospitalIcon sx={{ fontSize: 36, color: "white" }} />
          </Box>
          <Typography
            variant="h5"
            color="white"
            fontWeight={800}
            letterSpacing="-0.5px"
          >
            Medi<span style={{ color: "#90caf9" }}>Care</span>
          </Typography>
          <Typography
            variant="body2"
            sx={{ color: "rgba(255,255,255,0.75)", mt: 0.5 }}
          >
            Patient Portal
          </Typography>
        </Box>

        <Paper
          elevation={0}
          sx={{
            borderRadius: 4,
            overflow: "hidden",
            boxShadow: "0 20px 60px rgba(0,0,0,0.2)",
          }}
        >
          {/* Tabs */}
          <Tabs
            value={tab}
            onChange={(_, v) => {
              setTab(v);
              setError("");
              setSuccess("");
            }}
            variant="fullWidth"
            sx={{
              bgcolor: BG,
              "& .MuiTab-root": { fontWeight: 600, fontSize: 14, py: 2 },
              "& .MuiTabs-indicator": { bgcolor: PRIMARY, height: 3 },
              "& .Mui-selected": { color: `${PRIMARY} !important` },
            }}
          >
            <Tab label="Login" />
            <Tab label="Register" />
          </Tabs>

          <Box sx={{ p: 4 }}>
            {error && (
              <Alert severity="error" sx={{ mb: 2, borderRadius: 2 }}>
                {error}
              </Alert>
            )}
            {success && (
              <Alert severity="success" sx={{ mb: 2, borderRadius: 2 }}>
                {success}
              </Alert>
            )}

            {/* LOGIN */}
            {tab === 0 && (
              <>
                <Typography
                  variant="h6"
                  fontWeight={700}
                  mb={2.5}
                  color="#0d2a2a"
                >
                  Welcome back 👋
                </Typography>
                <TextField
                  fullWidth
                  label="Email Address"
                  type="email"
                  value={loginForm.email}
                  onChange={(e) =>
                    setLoginForm({ ...loginForm, email: e.target.value })
                  }
                  sx={fieldSx}
                  InputProps={{
                    startAdornment: (
                      <InputAdornment position="start">
                        <EmailIcon sx={{ color: PRIMARY, fontSize: 20 }} />
                      </InputAdornment>
                    ),
                  }}
                />
                <TextField
                  fullWidth
                  label="Password"
                  type={showPass ? "text" : "password"}
                  value={loginForm.password}
                  onChange={(e) =>
                    setLoginForm({ ...loginForm, password: e.target.value })
                  }
                  onKeyDown={(e) => e.key === "Enter" && handleLogin()}
                  sx={fieldSx}
                  InputProps={{
                    startAdornment: (
                      <InputAdornment position="start">
                        <LockIcon sx={{ color: PRIMARY, fontSize: 20 }} />
                      </InputAdornment>
                    ),
                    endAdornment: (
                      <InputAdornment position="end">
                        <IconButton
                          onClick={() => setShowPass(!showPass)}
                          edge="end"
                        >
                          {showPass ? (
                            <VisibilityOffIcon />
                          ) : (
                            <VisibilityIcon />
                          )}
                        </IconButton>
                      </InputAdornment>
                    ),
                  }}
                />
                <Button
                  fullWidth
                  variant="contained"
                  size="large"
                  onClick={handleLogin}
                  disabled={loading}
                  sx={{
                    mt: 1,
                    borderRadius: 3,
                    py: 1.5,
                    fontWeight: 700,
                    fontSize: 15,
                    background: `linear-gradient(90deg, ${PRIMARY_DARK}, ${PRIMARY})`,
                    boxShadow: "0 4px 16px rgba(25,118,210,0.3)",
                  }}
                >
                  {loading ? (
                    <CircularProgress size={22} color="inherit" />
                  ) : (
                    "Login"
                  )}
                </Button>
                <Typography
                  variant="body2"
                  align="center"
                  mt={2}
                  color="text.secondary"
                >
                  Don't have an account?{" "}
                  <span
                    style={{
                      color: PRIMARY,
                      fontWeight: 600,
                      cursor: "pointer",
                    }}
                    onClick={() => setTab(1)}
                  >
                    Register here
                  </span>
                </Typography>
              </>
            )}

            {/* REGISTER */}
            {tab === 1 && (
              <>
                <Typography
                  variant="h6"
                  fontWeight={700}
                  mb={2.5}
                  color="#0d2a2a"
                >
                  Create Account 🏥
                </Typography>
                <TextField
                  fullWidth
                  label="Full Name"
                  value={registerForm.fullName}
                  onChange={(e) =>
                    setRegisterForm({
                      ...registerForm,
                      fullName: e.target.value,
                    })
                  }
                  sx={fieldSx}
                  InputProps={{
                    startAdornment: (
                      <InputAdornment position="start">
                        <PersonIcon sx={{ color: PRIMARY, fontSize: 20 }} />
                      </InputAdornment>
                    ),
                  }}
                />
                <TextField
                  fullWidth
                  label="Email Address"
                  type="email"
                  value={registerForm.email}
                  onChange={(e) =>
                    setRegisterForm({ ...registerForm, email: e.target.value })
                  }
                  sx={fieldSx}
                  InputProps={{
                    startAdornment: (
                      <InputAdornment position="start">
                        <EmailIcon sx={{ color: PRIMARY, fontSize: 20 }} />
                      </InputAdornment>
                    ),
                  }}
                />
                <TextField
                  fullWidth
                  label="Phone Number"
                  value={registerForm.phone}
                  onChange={(e) => {
                    const val = e.target.value.replace(/\D/g, "").slice(0, 10);
                    setRegisterForm({ ...registerForm, phone: val });
                  }}
                  sx={fieldSx}
                  inputProps={{ maxLength: 10, inputMode: "numeric" }}
                  helperText="Must be exactly 10 digits"
                  InputProps={{
                    startAdornment: (
                      <InputAdornment position="start">
                        <PhoneIcon sx={{ color: PRIMARY, fontSize: 20 }} />
                      </InputAdornment>
                    ),
                  }}
                />
                <TextField
                  fullWidth
                  label="Password"
                  type={showPass ? "text" : "password"}
                  value={registerForm.password}
                  onChange={(e) =>
                    setRegisterForm({
                      ...registerForm,
                      password: e.target.value,
                    })
                  }
                  sx={fieldSx}
                  helperText="Minimum 6 characters"
                  InputProps={{
                    startAdornment: (
                      <InputAdornment position="start">
                        <LockIcon sx={{ color: PRIMARY, fontSize: 20 }} />
                      </InputAdornment>
                    ),
                    endAdornment: (
                      <InputAdornment position="end">
                        <IconButton
                          onClick={() => setShowPass(!showPass)}
                          edge="end"
                        >
                          {showPass ? (
                            <VisibilityOffIcon />
                          ) : (
                            <VisibilityIcon />
                          )}
                        </IconButton>
                      </InputAdornment>
                    ),
                  }}
                />
                <TextField
                  fullWidth
                  label="Confirm Password"
                  type="password"
                  value={registerForm.confirmPassword}
                  onChange={(e) =>
                    setRegisterForm({
                      ...registerForm,
                      confirmPassword: e.target.value,
                    })
                  }
                  sx={fieldSx}
                  InputProps={{
                    startAdornment: (
                      <InputAdornment position="start">
                        <LockIcon sx={{ color: PRIMARY, fontSize: 20 }} />
                      </InputAdornment>
                    ),
                  }}
                />
                <Button
                  fullWidth
                  variant="contained"
                  size="large"
                  onClick={handleRegister}
                  disabled={loading}
                  sx={{
                    mt: 1,
                    borderRadius: 3,
                    py: 1.5,
                    fontWeight: 700,
                    fontSize: 15,
                    background: `linear-gradient(90deg, ${PRIMARY_DARK}, ${PRIMARY})`,
                    boxShadow: "0 4px 16px rgba(25,118,210,0.3)",
                  }}
                >
                  {loading ? (
                    <CircularProgress size={22} color="inherit" />
                  ) : (
                    "Create Account"
                  )}
                </Button>
                <Typography
                  variant="body2"
                  align="center"
                  mt={2}
                  color="text.secondary"
                >
                  Already have an account?{" "}
                  <span
                    style={{
                      color: PRIMARY,
                      fontWeight: 600,
                      cursor: "pointer",
                    }}
                    onClick={() => setTab(0)}
                  >
                    Login here
                  </span>
                </Typography>
              </>
            )}
          </Box>
        </Paper>

        <Typography
          variant="caption"
          align="center"
          display="block"
          mt={2}
          sx={{ color: "rgba(255,255,255,0.6)" }}
        >
          Admin?{" "}
          <Link
            to="/admin"
            style={{ color: "rgba(255,255,255,0.8)", fontWeight: 600 }}
          >
            Login here
          </Link>
        </Typography>
      </Box>
    </Box>
  );
}
